package packages

import (
	"strings"

	"github.com/t04dJ14n9/gig/importer"
	"github.com/t04dJ14n9/gig/value"
)

// init installs hand-written DirectCall wrappers for benchmark-hot stdlib
// methods. Package-level function wrappers are generated by gentool.
func init() {
	if pkg := importer.GetPackageByPath("strings"); pkg != nil {
		pkg.AddMethodDirectCall("Reader", "Len", directCallStringsReaderLen)
		pkg.AddMethodDirectCall("Replacer", "Replace", directCallStringsReplacerReplace)
	}
}

func directCallStringsReaderLen(recv value.Value, _ []value.Value) value.Value {
	if r, ok := valueAs[*strings.Reader](recv); ok && r != nil {
		return value.MakeInt(int64(r.Len()))
	}
	return value.MakeInt(0)
}

func directCallStringsReplacerReplace(recv value.Value, args []value.Value) value.Value {
	if r, ok := valueAs[*strings.Replacer](recv); ok && r != nil {
		return value.MakeString(r.Replace(args[0].Str()))
	}
	return value.MakeString("")
}

func valueAs[T any](v value.Value) (T, bool) {
	var zero T
	if rv, ok := v.Reflect(); ok && rv.IsValid() {
		if got, ok := rv.Interface().(T); ok {
			return got, true
		}
	}
	if got, ok := v.Interface().(T); ok {
		return got, true
	}
	return zero, false
}
